/**
 * Builds the expanded gag-expression assets as standalone sheets.
 *
 * Important: this script intentionally does NOT overwrite the base
 * hatchling/effects runtime sheets. The gag body frames and notes effect
 * live in separate files so a future renderer change can opt into them
 * without risking the existing pet animation atlas.
 *
 * Pixels come from source/gag-expression-pack-master.png, generated by the
 * image model against the existing hatchling sheet as reference. This script
 * only chroma-keys, crops, quantizes, pads, packs, and resizes.
 */
import fs from 'node:fs/promises';
import path from 'node:path';
import sharp from '../../../overlay/node_modules/sharp/dist/index.mjs';

const root = path.resolve(import.meta.dirname, '..');
const masterPath = path.join(root, 'source', 'gag-expression-pack-master.png');
const gagPng = path.join(root, 'hatchling', 'hatchling-gag-expressions.png');
const gagJson = path.join(root, 'hatchling', 'hatchling-gag-expressions.json');
const notesPng = path.join(root, 'effects', 'effects-notes.png');
const notesJson = path.join(root, 'effects', 'effects-notes.json');
const bottlePng = path.join(root, 'items', 'prop-drink-bottle-sprite-16x16.png');

const PET_CELL = 184;
const PET_COLUMNS = 8;
const NOTE_CELL = 88;
const MAGENTA = [255, 0, 255];
const SWEETIE16 = [
  [0x1a, 0x1c, 0x2c],
  [0x5d, 0x27, 0x5d],
  [0xb1, 0x3e, 0x53],
  [0xef, 0x7d, 0x57],
  [0xff, 0xcd, 0x75],
  [0xa7, 0xf0, 0x70],
  [0x38, 0xb7, 0x64],
  [0x25, 0x71, 0x79],
  [0x29, 0x36, 0x6f],
  [0x3b, 0x5d, 0xc9],
  [0x41, 0xa6, 0xf6],
  [0x73, 0xef, 0xf7],
  [0xf4, 0xf4, 0xf4],
  [0x94, 0xb0, 0xc2],
  [0x56, 0x6c, 0x86],
  [0x33, 0x3c, 0x57],
];

const gagFrames = [
  ['sneeze', 120, [355, 52, 483, 191]],
  ['sneeze', 90, [594, 78, 723, 191]],
  ['sneeze', 80, [849, 52, 979, 191]],
  ['sneeze', 150, [1064, 52, 1192, 191]],
  ['yawn', 150, [355, 237, 483, 379]],
  ['yawn', 250, [590, 229, 723, 379]],
  ['yawn', 200, [850, 237, 974, 379]],
  ['yawn', 200, [1065, 237, 1193, 379]],
  ['dance', 110, [223, 425, 345, 557]],
  ['dance', 110, [456, 434, 575, 554]],
  ['dance', 110, [685, 434, 813, 555]],
  ['dance', 110, [933, 431, 1051, 554]],
  ['dance', 110, [1155, 425, 1277, 557]],
  ['dance', 110, [1370, 434, 1490, 555]],
  ['drink-break', 120, [161, 594, 343, 724]],
  ['drink-break', 120, [405, 592, 570, 724]],
  ['drink-break', 130, [680, 592, 819, 724]],
  ['drink-break', 130, [918, 599, 1061, 728]],
  ['drink-break', 110, [1146, 602, 1291, 728]],
  ['drink-break', 110, [1405, 593, 1586, 725]],
].map(([tag, duration, box]) => ({ tag, duration, box: toBox(box) }));

const noteFrames = [
  ['notes', 200, [228, 788, 292, 855]],
  ['notes', 200, [360, 788, 425, 852]],
].map(([tag, duration, box]) => ({ tag, duration, box: toBox(box) }));

const bottleBox = toBox([510, 778, 567, 863]);

function toBox([left, top, right, bottom]) {
  return { left, top, width: right - left + 1, height: bottom - top + 1 };
}

async function readRgba(file) {
  const { data, info } = await sharp(file).ensureAlpha().raw().toBuffer({ resolveWithObject: true });
  return { data, width: info.width, height: info.height };
}

function isPlatePixel(r, g, b) {
  const dr = r - MAGENTA[0];
  const dg = g - MAGENTA[1];
  const db = b - MAGENTA[2];
  const distance = Math.sqrt(dr * dr + dg * dg + db * db);
  return distance < 165 || (r > 180 && b > 150 && g < 95);
}

function nearestPaletteColor(r, g, b) {
  let best = SWEETIE16[0];
  let bestDistance = Number.POSITIVE_INFINITY;
  for (const color of SWEETIE16) {
    const dr = r - color[0];
    const dg = g - color[1];
    const db = b - color[2];
    const distance = dr * dr + dg * dg + db * db;
    if (distance < bestDistance) {
      best = color;
      bestDistance = distance;
    }
  }
  return best;
}

function cropAndKey(master, box) {
  const out = Buffer.alloc(box.width * box.height * 4);
  for (let y = 0; y < box.height; y += 1) {
    for (let x = 0; x < box.width; x += 1) {
      const src = ((box.top + y) * master.width + box.left + x) * 4;
      const dst = (y * box.width + x) * 4;
      const r = master.data[src];
      const g = master.data[src + 1];
      const b = master.data[src + 2];
      if (isPlatePixel(r, g, b)) {
        out[dst + 3] = 0;
        continue;
      }
      const [qr, qg, qb] = nearestPaletteColor(r, g, b);
      out[dst] = qr;
      out[dst + 1] = qg;
      out[dst + 2] = qb;
      out[dst + 3] = 255;
    }
  }
  return { data: out, width: box.width, height: box.height };
}

async function padToCell(crop, cell, { bottomMargin = 12 } = {}) {
  const left = Math.max(0, Math.round((cell - crop.width) / 2));
  const top = Math.max(0, cell - bottomMargin - crop.height);
  return sharp({ create: { width: cell, height: cell, channels: 4, background: { r: 0, g: 0, b: 0, alpha: 0 } } })
    .composite([{ input: crop.data, raw: { width: crop.width, height: crop.height, channels: 4 }, left, top }])
    .png()
    .toBuffer();
}

function tagRanges(frames) {
  const ranges = [];
  frames.forEach((frame, index) => {
    const current = ranges[ranges.length - 1];
    if (current?.name === frame.tag) {
      current.to = index;
    } else {
      ranges.push({ name: frame.tag, from: index, to: index, direction: 'forward' });
    }
  });
  return ranges;
}

function asepriteJson(image, frames, size) {
  return {
    frames: frames.map((frame, index) => ({
      filename: `${path.basename(image, '.png')} ${index}.aseprite`,
      frame: { x: frame.x, y: frame.y, w: frame.w, h: frame.h },
      duration: frame.duration,
    })),
    meta: {
      app: 'Tokengochi image-model pipeline',
      version: '1.0',
      image,
      format: 'RGBA8888',
      size,
      scale: '1',
      frameTags: tagRanges(frames),
    },
  };
}

async function buildSheet(master, specs, destinationPng, destinationJson, imageName, cell, columns, bottomMargin) {
  const tmpPng = `${destinationPng}.tmp.png`;
  const cells = [];
  for (const spec of specs) {
    const crop = cropAndKey(master, spec.box);
    cells.push({
      input: await padToCell(crop, cell, { bottomMargin }),
      tag: spec.tag,
      duration: spec.duration,
    });
  }

  const rows = Math.ceil(cells.length / columns);
  const composites = cells.map((frame, index) => ({
    input: frame.input,
    left: (index % columns) * cell,
    top: Math.floor(index / columns) * cell,
  }));

  await sharp({ create: { width: columns * cell, height: rows * cell, channels: 4, background: { r: 0, g: 0, b: 0, alpha: 0 } } })
    .composite(composites)
    .png()
    .toFile(tmpPng);
  await quantizePngInPlace(tmpPng);
  await fs.rename(tmpPng, destinationPng);

  const frames = cells.map((frame, index) => ({
    tag: frame.tag,
    duration: frame.duration,
    x: (index % columns) * cell,
    y: Math.floor(index / columns) * cell,
    w: cell,
    h: cell,
  }));
  await fs.writeFile(destinationJson, `${JSON.stringify(asepriteJson(imageName, frames, { w: columns * cell, h: rows * cell }), null, 2)}\n`);
}

async function writeBottle(master) {
  const tmpPng = `${bottlePng}.tmp.png`;
  const crop = cropAndKey(master, bottleBox);
  const input = await sharp(crop.data, { raw: { width: crop.width, height: crop.height, channels: 4 } })
    .resize({ width: 12, height: 16, fit: 'inside', kernel: 'nearest' })
    .png()
    .toBuffer({ resolveWithObject: true });

  await sharp({ create: { width: 16, height: 16, channels: 4, background: { r: 0, g: 0, b: 0, alpha: 0 } } })
    .composite([{ input: input.data, left: Math.floor((16 - input.info.width) / 2), top: 16 - input.info.height }])
    .png()
    .toFile(tmpPng);
  await quantizePngInPlace(tmpPng);
  await fs.rename(tmpPng, bottlePng);
}

async function quantizePngInPlace(file) {
  const { data, info } = await sharp(file).ensureAlpha().raw().toBuffer({ resolveWithObject: true });
  for (let i = 0; i < data.length; i += 4) {
    if (data[i + 3] < 128) {
      data[i] = 0;
      data[i + 1] = 0;
      data[i + 2] = 0;
      data[i + 3] = 0;
      continue;
    }
    const [r, g, b] = nearestPaletteColor(data[i], data[i + 1], data[i + 2]);
    data[i] = r;
    data[i + 1] = g;
    data[i + 2] = b;
    data[i + 3] = 255;
  }
  await sharp(data, { raw: { width: info.width, height: info.height, channels: 4 } }).png().toFile(file);
}

const master = await readRgba(masterPath);
await buildSheet(master, gagFrames, gagPng, gagJson, 'hatchling-gag-expressions.png', PET_CELL, PET_COLUMNS, 12);
await buildSheet(master, noteFrames, notesPng, notesJson, 'effects-notes.png', NOTE_CELL, 2, 10);
await writeBottle(master);
